diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..473ea1f626b8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2031,6 +2031,49 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
   }

+  // C2 - ((C1 - X) & M) --> X & K
+  // where M = -N (N is power of 2), C2 = C1 & M, and K = C1 + (C1 mod N) * (N - 1)
+  // Example: 64 - ((71 - X) & -8) --> X & 120
+  if (Constant *C2Const = dyn_cast<Constant>(Op0)) {
+    const APInt *C1, *M;
+    Value *X;
+    if (match(Op1, m_And(m_OneUse(m_Sub(m_APInt(C1), m_Value(X))), m_APInt(M)))) {
+      // M should be -N where N is a power of 2 (i.e., M clears low bits)
+      APInt N = -*M;
+      if (N.isPowerOf2()) {
+        const APInt &C2Val = cast<ConstantInt>(C2Const)->getValue();
+        // C2 must equal C1 & M for the transform to be valid
+        if (C2Val == (*C1 & *M)) {
+          // K = C1 + (C1 mod N) * (N - 1)
+          // Since C1 mod N = C1 & (N - 1), we have:
+          APInt C1modN = *C1 & (N - 1);
+          APInt K = *C1 + C1modN * (N - 1);
+          return BinaryOperator::CreateAnd(X, ConstantInt::get(I.getType(), K));
+        }
+      }
+    }
+  }
+
+  // C - ((C1 - X) & M) --> (X & M) + (C - (C1 & M))
+  // where M = -N (N is power of 2)
+  // Example: 33 - ((71 - X) & -8) --> (X & -8) - 31
+  if (Constant *CConst = dyn_cast<Constant>(Op0)) {
+    const APInt *C1, *M;
+    Value *X;
+    if (match(Op1, m_And(m_OneUse(m_Sub(m_APInt(C1), m_Value(X))), m_APInt(M)))) {
+      // M should be -N where N is a power of 2 (i.e., M clears low bits)
+      APInt N = -*M;
+      if (N.isPowerOf2()) {
+        const APInt &CVal = cast<ConstantInt>(CConst)->getValue();
+        // Compute (X & M) + (C - (C1 & M))
+        APInt C1andM = *C1 & *M;
+        APInt AddConst = CVal - C1andM;
+        Value *AndVal = Builder.CreateAnd(X, ConstantInt::get(I.getType(), *M));
+        return BinaryOperator::CreateAdd(AndVal, ConstantInt::get(I.getType(), AddConst));
+      }
+    }
+  }
+
   const APInt *Op0C;
   if (match(Op0, m_APInt(Op0C)) && Op0C->isMask()) {
     // Turn this into a xor if LHS is 2^n-1 and the remaining bits are known
